var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이미 짐작하고 계시겠지만, 저희 세계는 필연적인 멸망을 앞두고 있습니다.","JPN":"すでにおわかりとは思いますが、私たちの世界は避けることのできない滅亡を前にしています。","ENG":"As you may have already guessed, our world is faced with an impending doom.","TWN":"你應該已經有猜到，我們的世界正面臨著無法避免的滅亡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그리고 저희는 그 멸망으로부터 세계를 구하는 길을 찾아, 마침내 이 세계에 도달한 거죠.","JPN":"そして、私たちはその滅亡から世界を救う方法を探し求めて、この世界にたどり着きました。","ENG":"We arrived in this world in search of a way to prevent ours from collapsing.","TWN":"為了尋找拯救世界脫離滅亡的出路，我們最終來到這個世界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"저희 스스로의 힘으로 이곳에 다다르기까지 수없이 많은 시련이 있었지만.","JPN":"自力でこの世界に到達するまでには数えきれない程の試練がありましたが。","ENG":"We had to go through countless trials to reach here on our own.","TWN":"在我們憑著我們自己的力量來到這個世界之前，雖然已經經歷過無數的考驗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"바로 지금, 당신과의 만남으로서 어쩌면 저희는 비로소 활로를 찾았을지도 모르겠군요.","JPN":"この瞬間、あなたと会うことで私たちは初めて活路を見出せたのかもしれません。","ENG":"But meeting you now gives me hope that we can save our world.","TWN":"不過現在遇見你，或許就代表著我們找到了活路。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그동안 함께한 시간을 통해… 이 길이 틀리지 않았다는 확신을 받았으니까요.","JPN":"今まで共にしてきた時間の中で……確信しましたから。この道に間違いはなかったと。","ENG":"Through our time together... I am confident that this is the right path.","TWN":"因為經過這段時間的相處……我們確信這條路是正確的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"후후, 가능하다면 앞서간 대원들에게도 이 세계의 풍경을 보여주고 싶네요.","JPN":"ふふ、できれば先立った隊員たちにもこの世界の風景を見せてあげたかったです。","ENG":"Haha, I only wish that I could show this world's scenery to our fallen comrades.","TWN":"呵呵，如果可以，真想讓那些犧牲的隊員也看看這個世界的風景。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"막다른 길 넘어, 마침내 다다른 이 풍경을….","JPN":"袋小路を抜け、最後にたどり着いたこの風景を……","ENG":"A new hope, beyond the dead-end road...","TWN":"越過死路，終於抵達的這個風景……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"크흠, 흠…!!","JPN":"コホン、コホン……！！","ENG":"Ahem, hmm...!!","TWN":"咳咳，咳……！！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"하지만 그것과 종신 계약은 별개라고요!","JPN":"でも、それと終身契約は別物です！","ENG":"Having said that, a lifetime contract is entirely something else!","TWN":"但這與終身契約是二回事！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이미 몇 번이나 말씀드렸지만, 당신은 좀 더 책임감을 가질 필요가 있습니다, 관리자님.","JPN":"すでに何度も申し上げていますが、あなたにはもう少し責任感というものが必要だと思います、管理者さん。","ENG":"I've told you many times before, but you need to be more responsible, Administrator.","TWN":"我說過很多次，你需要再多一點責任感，管理者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"당신이 무심코 내린 결정이 이 회사, 나아가 세계에 어떤 영향을 줄 지 아무도 모르니까요.","JPN":"あなたが適当に下した決定が、会社、しいては世界にどんな影響を及ぼすかわからないのですよ。","ENG":"Nobody knows how your decisions on a whim can affect the world, let alone the company.","TWN":"你無意中做出的決定，會對這個公司、對這個世界造成怎樣的影響，沒人知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"그러니까 지금부터 밀린 사무처리를 해결하고, 부조리한 과소비를 줄여나가도록 해요!","JPN":"ですから、今から溜まっている事務処理を片づけて、不条理な出費を削減していきましょう！","ENG":"So from now on, stop pushing back your administrative tasks and stop spending money on frivolous stuff!","TWN":"所以從現在開始，請處理掉累積的工作量，減少不合理的過度消費！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"무엇보다도 이 뒤의 종신 계약 같은 중요한 인사 안건은 반드시 저와 상담해 주시고요.","JPN":"何よりも、この後にある終身契約のような重要な人事案件は必ず私と相談するようにしてください。","ENG":"Above all, you should consult with me regarding important HR matters afterwards, including lifetime contracts.","TWN":"最重要的是，以後像終生契約這種重要的人事提案，請一定要先跟我商量。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"이 순간부터는 이 세계뿐만 아니라 저희 세계의 미래를 위해서라도 철저한 내사가 필요할 테니까요.","JPN":"この瞬間から、この世界だけでなく、私たちの世界の未来のためにも徹底的な内偵が必要となるでしょう。","ENG":"Because, from now on, I believe a thorough internal investigation is required for not only your world's future, but also ours.","TWN":"從此刻開始，不單是為了這個世界，也為了我們世界的未來，需要進行全面的內部調查。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"자, 계약서를 주세요.","JPN":"では、契約書をください。","ENG":"Now, hand the contract over to me.","TWN":"來吧，把合約給我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우리에겐 1분 1초도 낭비할 시간은 없으니까요.","JPN":"私たちは1分1秒も無駄にできません。","ENG":"We can't afford to waste time. Not for even a second.","TWN":"我們連一分一秒都不能浪費。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};